WITH "sample" AS (SELECT * EXCLUDE (_sf_sample_hash) FROM (SELECT t.*, ABS(HASH(*)) AS _sf_sample_hash FROM "FAKE_PROJECT"."DATASET"."ORDERS" AS t) WHERE MOD(_sf_sample_hash, 10) < 1 LIMIT 100000) SELECT "CUSTOMER_ID" FROM "sample" WHERE "CUSTOMER_ID" IS NOT NULL GROUP BY "CUSTOMER_ID" HAVING COUNT(*) > 1